import React from 'react';
import { useAuth } from '../contexts/AuthContext';
import { useTheme } from '../contexts/ThemeContext';

const Settings: React.FC = () => {
  const { user } = useAuth();
  const { theme, toggleTheme } = useTheme();

  return (
    <div className="space-y-6 max-w-4xl">
      <h2 className="text-2xl font-bold tracking-tight">Settings</h2>

      <div className="bg-card border rounded-lg overflow-hidden">
        <div className="p-6 border-b">
          <h3 className="text-lg font-medium">Profile Settings</h3>
          <p className="text-sm text-gray-500">Update your profile information and notification preferences.</p>

          <div className="mt-6 space-y-4 max-w-xl">
            <div>
              <label className="block text-sm font-medium mb-1">Username</label>
              <input type="text" disabled value={user?.username || ''} className="w-full px-3 py-2 border rounded-md bg-gray-50 disabled:text-gray-500" />
            </div>
            <div>
              <label className="block text-sm font-medium mb-1">Email Address</label>
              <input type="email" disabled value={user?.email || ''} className="w-full px-3 py-2 border rounded-md bg-gray-50 disabled:text-gray-500" />
            </div>
            <div>
              <label className="block text-sm font-medium mb-1">Role</label>
              <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-gray-100 text-gray-800">
                {user?.role}
              </span>
            </div>
          </div>
        </div>

        <div className="p-6">
          <h3 className="text-lg font-medium">Appearance</h3>
          <div className="mt-4 flex items-center justify-between">
            <div>
              <p className="text-sm font-medium text-gray-900 dark:text-gray-100">Theme Mode</p>
              <p className="text-sm text-gray-500">Toggle between light and dark themes.</p>
            </div>
            <button 
              onClick={toggleTheme}
              className="px-4 py-2 border rounded-md shadow-sm text-sm font-medium bg-white dark:bg-slate-700 hover:bg-gray-50 dark:hover:bg-slate-600 focus:outline-none"
            >
              {theme === 'light' ? 'Switch to Dark' : 'Switch to Light'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Settings;
